import json
from datetime import datetime

class DateTimeEncoder(json.JSONEncoder):
    def default(self, obj):
        if isinstance(obj, datetime):
            return obj.isoformat()
        return super().default(obj)

# 查看所有可能的实时数据表结构
tables = ['st_wdwv_r', 'st_wgrw_r', 'st_grw_r', 'st_was_r', 'st_river_r', 'st_rsvr_r']

for table in tables:
    try:
        sql = f"""
        SELECT COLUMN_NAME, DATA_TYPE 
        FROM INFORMATION_SCHEMA.COLUMNS 
        WHERE TABLE_SCHEMA = 'sl323' AND TABLE_NAME = '{table}'
        ORDER BY ORDINAL_POSITION
        """
        columns = query(sql)
        if columns:
            print(f"=== {table} ===")
            print(json.dumps(columns, cls=DateTimeEncoder, ensure_ascii=False, indent=2))
    except Exception as e:
        print(f"{table}: {e}")
    print()
"}

